{
  "questions": [
    {
      "format": "multipleChoice",
      "context": "Maya enters `https://reports.example.org/sales?month=May` into a new browser tab.",
      "question": "How does the browser use this URL?",
      "options": [
        {
          "feedback": "Exactly. The scheme guides the secure connection, the hostname identifies what DNS must resolve, and the path and query become part of the HTTP request target.",
          "isCorrect": true,
          "text": "Use HTTPS, resolve the hostname, then request the path and query"
        },
        {
          "feedback": "That mixes up DNS and HTTP. DNS resolves the hostname, not the path or query string.",
          "isCorrect": false,
          "text": "Resolve the full URL through DNS, then open an HTTP connection"
        },
        {
          "feedback": "The path does not identify the network destination. The hostname is resolved before the browser can contact the server.",
          "isCorrect": false,
          "text": "Connect using the path, then ask DNS to verify the hostname"
        },
        {
          "feedback": "HTTPS still needs a network destination and secure connection before application data can be exchanged.",
          "isCorrect": false,
          "text": "Send the query directly, then establish security after receiving data"
        }
      ]
    },
    {
      "format": "sortOrder",
      "question": "Put the main stages of a new HTTPS navigation in order. Each stage depends on the one before it.",
      "items": [
        "Interpret the URL and identify the hostname",
        "Resolve the hostname through DNS",
        "Establish the TCP connection",
        "Complete the TLS handshake",
        "Send the HTTP request and receive response bytes",
        "Parse the downloaded resources and render the page"
      ],
      "feedback": "The browser first interprets the destination, resolves its network address, and creates a transport connection. HTTPS adds TLS before HTTP data is exchanged. The returned bytes can then be parsed into page structures and rendered."
    },
    {
      "format": "selectImage",
      "question": "Which screenshot most strongly suggests that the HTML arrived and was parsed, but the stylesheet did not load?",
      "options": [
        {
          "feedback": "Right. Visible headings, links, and lists show that HTML was parsed, while the browser-default appearance points to missing CSS.",
          "isCorrect": true,
          "prompt": "A page with visible headings, blue underlined links, bullet lists, and plain browser-default spacing"
        },
        {
          "feedback": "A completely blank page does not provide clear evidence that the HTML was successfully parsed.",
          "isCorrect": false,
          "prompt": "A completely white page with no visible content or browser message"
        },
        {
          "feedback": "A DNS error appears before HTML can be downloaded or parsed.",
          "isCorrect": false,
          "prompt": "A browser error page showing a crossed-out globe and a short hostname error"
        },
        {
          "feedback": "A certificate warning indicates a TLS problem, which occurs before the browser receives the page's HTML.",
          "isCorrect": false,
          "prompt": "A browser security warning with a large lock symbol and certificate alert"
        }
      ]
    },
    {
      "format": "multipleChoice",
      "context": "A network trace shows that DNS returned an IP address immediately. The browser then waits until its connection attempt times out, without sending an HTTP request.",
      "question": "Where is the failure most likely?",
      "options": [
        {
          "feedback": "DNS already succeeded because an IP address was returned. The timeout occurred during the next stage.",
          "isCorrect": false,
          "text": "The DNS lookup"
        },
        {
          "feedback": "Yes. The browser knows the address but cannot establish the transport connection, so HTTP has not started.",
          "isCorrect": true,
          "text": "The TCP connection"
        },
        {
          "feedback": "TLS cannot begin successfully until the underlying connection is established.",
          "isCorrect": false,
          "text": "The TLS handshake"
        },
        {
          "feedback": "No HTTP request was sent, so the server has not yet produced an HTTP response.",
          "isCorrect": false,
          "text": "The HTTP response"
        }
      ]
    },
    {
      "format": "fillBlank",
      "question": "Complete the two networking relationships.",
      "template": "DNS resolves a hostname to an [BLANK]. For HTTPS over TCP, TLS creates an [BLANK] channel before HTTP data is exchanged.",
      "answers": [
        "IP address",
        "encrypted, authenticated"
      ],
      "distractors": [
        "HTML document",
        "HTTP status",
        "uncompressed",
        "anonymous"
      ],
      "feedback": "An IP address gives the browser a network destination. TLS then encrypts the connection and authenticates the server before sensitive HTTP request and response data travels across it."
    },
    {
      "format": "multipleChoice",
      "context": "The initial HTML arrives quickly, but it references a large stylesheet that downloads slowly. The browser delays the first fully styled display.",
      "question": "What best explains the delay?",
      "options": [
        {
          "feedback": "Exactly. Parsing HTML can reveal more resources to request, and CSS is needed to calculate how elements should look before final painting.",
          "isCorrect": true,
          "text": "Parsing discovered CSS needed for rendering"
        },
        {
          "feedback": "DNS resolves hosts; it does not inspect style rules or decide how the page should be painted.",
          "isCorrect": false,
          "text": "DNS is processing the stylesheet rules"
        },
        {
          "feedback": "TLS protects transferred data but does not convert CSS into visible pixels.",
          "isCorrect": false,
          "text": "TLS is converting CSS into pixels"
        },
        {
          "feedback": "The HTML request can finish while additional resource requests are still underway.",
          "isCorrect": false,
          "text": "The original HTTP request is still unsent"
        }
      ]
    },
    {
      "format": "selectImage",
      "question": "A page takes a long time because the server is slow to begin its response, not because the response file downloads slowly. Which waterfall bar fits?",
      "options": [
        {
          "feedback": "Correct. A long wait before the first response byte points to server processing or network latency before the response begins.",
          "isCorrect": true,
          "prompt": "A single request bar with short DNS, connect, and send segments, a very long waiting segment, then a short download segment"
        },
        {
          "feedback": "This pattern points to slow transfer of the response body after the server has already started responding.",
          "isCorrect": false,
          "prompt": "A single request bar with short setup and waiting segments, followed by a very long download segment"
        },
        {
          "feedback": "This suggests the delay occurred while resolving the hostname, before contacting the server.",
          "isCorrect": false,
          "prompt": "A single request bar with a very long DNS segment followed by short connect, wait, and download segments"
        },
        {
          "feedback": "This suggests difficulty creating the network connection rather than slow server processing.",
          "isCorrect": false,
          "prompt": "A single request bar with short DNS, a very long connect segment, then short wait and download segments"
        }
      ]
    },
    {
      "format": "matchColumns",
      "pairs": [
        {
          "left": "Certificate name mismatch",
          "right": "TLS handshake"
        },
        {
          "left": "HTTP 503 status",
          "right": "Server response"
        },
        {
          "left": "Element exists in the DOM but is invisible",
          "right": "Styling or rendering"
        }
      ],
      "question": "Match each debugging clue to the lifecycle stage it most directly identifies."
    }
  ]
}

